module top_module(
   input bit_one,
   input bit_two,
   input carry_in,
   output result,
   output carry_out
   );wire   sum_xor;
  wire   carry_or;
  wire   in_and;

  assign sum_xor = bit_one ^ bit_two;
  assign carry_or = sum_xor & carry_in;
  assign in_and = bit_one & bit_two;
  assign result   = sum_xor ^ carry_in;
  assign carry_out = carry_or | in_and;endmodule
